event.script:
var pageIndex = xfa.layout.page(this);
if (pageIndex > 1) {
    var pageName = "Page1",
        somExp = this.somExpression,
        p = this.parent;
    /* Compute the page name containing the field */
    while (p) {
        if (p.className === "pageArea") {
            pageName = p.name;
            break;
        }
        p = p.parent;
    }
    /* Replace page index with 0 to get the first instance of the field*/
    var startIndex = somExp.indexOf(pageName + "["),
        endIndex = somExp.indexOf("]", startIndex) + 1;
    somExp = somExp.substr(0, startIndex) + pageName + "[0]" + somExp.substr(endIndex);
    var node = xfa.resolveNode(somExp);
    /* Set the value of the field to that of the first instance */
    if (node) {
        this.rawValue = node.rawValue;
    }
}

