event.script:
this.x = (xfa.layout.x(this.parent, "mm") + xfa.layout.w(this.parent.indent, "mm")) + "mm";
if (this.rawValue != null && this.rawValue != "") // set margin, if there is a bullet to be applied
{
var currW = xfa.layout.w(this, "mm"); // current width in mm
var tab = this.parent.dataNode.parent.parent.arabicTab.value; // a single tab value (in mm)

try
{
if (this.parent.dataNode.format.bullet.type) // check if the type is specified -- just being safe here, rather than sorry (especially when reloading letters that may not have this value set)
{
var numberingType = this.parent.dataNode.format.bullet.type.value; // get the type of numbering used
if (numberingType == "TYPE_NUMBER_ROMANUPPER" || numberingType == "TYPE_NUMBER_ROMANLOWER")
tab = this.parent.dataNode.parent.parent.romanTab.value; // increase minimum tab value for roman numbers (since they can really be large in width)
}
} catch(err)
{
// do nothing - perhaps there was not 'type' info in the bullet
}

// evaluate the scale and assign the minimum width
var scale = Math.ceil(currW/tab);
this.minW = (scale * tab) + "mm";

this.margin.rightInset = "1.524mm";
}

this.w = (xfa.layout.w(this.parent, "mm") - xfa.layout.w(this.parent.bulletText, "mm") - xfa.layout.w(this.parent.indent, "mm")) + "mm";
