variables.script:
					// This first part of the script block is about establishing the
					// communication with the host HTML.
					____t0____ = new Date().getTime();

					function fb_docReady(doc)
					{
						if (xfa.host.name == "Acrobat" && typeof(doc.hostContainer) != "undefined")
						{
							console.clear();
							__curDoc__ = doc;
							new__fb__(doc);
							doc.__fb__.tDocReady = timeit();
							fb_processUrl(doc);
							fbDebug(3, "PDF: In event docReady");
							fb_SetupCommunicationsWithTheHostHtml(doc);
						}
					}

					// Really want this to be a 'set one time' *global* object.
					function new__fb__(doc)
					{
						doc.__fb__ = new Object();
						doc.__fb__.t0 = new Date().getTime();
						if (____t0____ < doc.__fb__.t0)
							doc.__fb__.t0 = ____t0____;
						doc.__fb__.doc = doc;
						doc.__fb__.pdfFileSize = doc.filesize;
						doc.__fb__.postReadyDelay = 0;
						doc.__fb__.postInstantiationDelay = 0;
						doc.__fb__.postTheInitializedMsg = fb_postTheInitializedMsg;
						doc.__fb__.testIfConnected = fb_testIfConnected;
						doc.__fb__.processMessage = fb_processMessage;
						doc.__fb__.preConnectedDebugLevel = 6;
						doc.__fb__.postConnectedDebugLevel = 0;
						doc.__fb__.fbDebugLevel	= doc.__fb__.preConnectedDebugLevel;
						doc.__fb__.messageReceived = false;
						doc.__fb__.timeout = null;
						doc.__fb__.communicationInitializationAttempts = 0;

						doc.__fb__.messageHandlerObject = new Object();
						doc.__fb__.messageHandlerObject.id			= "The PDF document's messageHandler object";
						doc.__fb__.messageHandlerObject.onMessage	= fb_HandleIncomingMessage;
						doc.__fb__.messageHandlerObject.onError		= fb_HandleErrorFromPostMessage;
						doc.__fb__.messageHandlerObject.onDisclose	= fb_DetermineWhetherToDisclose;
						doc.__fb__.messageHandlerObject.doc			= doc;
						fbDebug(9, "PDF FormBridge: The globals are initialized");
					}

					function timeit()
					{
						var t = new Date().getTime();
						t -= __curDoc__.__fb__.t0;
						return ("T" + t + ": ");
					}

					function fb_processUrl(doc)
					{
						var url = doc.URL + "&fbDebug=9,1,2#&";
						var i = url.indexOf("?fbDebug=") + 9;
						if (i < 9) i = url.indexOf("&fbDebug=") + 9;
						var j = url.substr(i).indexOf("#");
						var k = url.substr(i).indexOf("&");
						if (k < j) j = k;
						var fbDebugStr = url.substr(i, j);
						doc.__fb__.fbDebugStr = fbDebugStr;
						var fbDebugParms = new Array();
						fbDebugParms = fbDebugStr.split(",");
						fbDebug(9, "fbDebugParms: '" + fbDebugParms + "'  length: " + fbDebugParms.length);
						if (fbDebugParms.length > 0)
							doc.__fb__.preConnectedDebugLevel = parseInt(fbDebugParms[0]);
						if (fbDebugParms.length > 1)
							doc.__fb__.postConnectedDebugLevel = parseInt(fbDebugParms[1]);
						if (fbDebugParms.length > 2)
							doc.__fb__.postReadyDelay = parseFloat(fbDebugParms[2]);
						if (fbDebugParms.length > 3)
							doc.__fb__.postInstantiationDelay = parseFloat(fbDebugParms[3]);		// used by only the HTML host
						doc.__fb__.fbDebugLevel = doc.__fb__.preConnectedDebugLevel;
						if (doc.__fb__.postReadyDelay <= 0) doc.__fb__.postReadyDelay = .001;
						doc.__fb__.postReadyDelay = parseInt(doc.__fb__.postReadyDelay * 1000);
						doc.__fb__.testForConnectionDelay = 1000;
					}

					function fb_SetupCommunicationsWithTheHostHtml(doc)
					{
						__curDoc__ = doc;
						fbDebug(9, "PDF: Give PDF our filled-out messageHandler object");
						doc.__fb__.messageHandlerObject.doc			= doc;
						doc.__fb__.doc.hostContainer.messageHandler = doc.__fb__.messageHandlerObject;
						fbDebug(8, "PDF: Waiting " + doc.__fb__.postReadyDelay + " millisecond(s) before posting the first [initialized, 1]");
						doc.__fb__.timeout = app.setTimeOut("__curDoc__.__fb__.postTheInitializedMsg()", doc.__fb__.postReadyDelay);
						return;
					}

					function fb_postTheInitializedMsg()
					{
						__curDoc__.__fb__.communicationInitializationAttempts++;
						fb_clearTimeout();
						if (typeof(__curDoc__.__fb__.tInitializedMsg) == "undefined")
							__curDoc__.__fb__.tInitializedMsg = timeit();

						// Keep setting our messageHandler object to ensure we are always listening
						__curDoc__.hostContainer.messageHandler = __curDoc__.__fb__.messageHandlerObject;
						fbDebug(8, "PDF: Posting [initialized,1] #" + (__curDoc__.__fb__.communicationInitializationAttempts+1));
						var initMsgArr = new Array();
						initMsgArr.push("initialized");
						initMsgArr.push("1");
						__curDoc__.hostContainer.postMessage(initMsgArr);

						if (__curDoc__.__fb__.testForConnectionDelay < 2000)
							__curDoc__.__fb__.testForConnectionDelay *= 2;
						fbDebug(8, "PDF: Waiting " + __curDoc__.__fb__.testForConnectionDelay + " millisecond(s) before seeing if connected");
						__curDoc__.__fb__.timeout = app.setTimeOut("__curDoc__.__fb__.testIfConnected()", __curDoc__.__fb__.testForConnectionDelay);
					}


					function fb_testIfConnected()
					{
						fbDebug(7, "PDF: Testing if connected yet: " + __curDoc__.__fb__.messageReceived);
						fb_clearTimeout();
						if (__curDoc__.__fb__.messageReceived == true)
							return;

						fbDebug(6, "PDF: Issuing connect attempt #" + (__curDoc__.__fb__.communicationInitializationAttempts+1));
						fb_postTheInitializedMsg();
						return;
					}

					function fb_clearTimeout()
					{
						if (__curDoc__.__fb__.timeout != null)
						{
							app.clearTimeOut(__curDoc__.__fb__.timeout);
							__curDoc__.__fb__.timeout = null;
						}
					}


					function fb_HandleIncomingMessage(arrayOfStrings)
					{
						__curDoc__ = this.doc;
						fbDebug(8, "PDF: Got a message from the HTML host: '" + arrayOfStrings + "'");
						if (__curDoc__.__fb__.messageReceived == false)
						{
							fbDebug(4, "Switching logging over to the flashlog");
							__curDoc__.__fb__.messageReceived = true;
							__curDoc__.__fb__.tConnected = timeit();
							var statsMsg = new Array();
							statsMsg.push("statistics");
							statsMsg.push("t0");
							statsMsg.push(""+__curDoc__.__fb__.t0+"");
							statsMsg.push("tDocReady");
							statsMsg.push(__curDoc__.__fb__.tDocReady);
							statsMsg.push("tInitializedMsg");
							statsMsg.push(__curDoc__.__fb__.tInitializedMsg);
							statsMsg.push("tConnected");
							statsMsg.push(__curDoc__.__fb__.tConnected);
							statsMsg.push("fileSize");
							statsMsg.push(__curDoc__.__fb__.pdfFileSize);
							statsMsg.push("nAttempts");
							statsMsg.push(""+(__curDoc__.__fb__.communicationInitializationAttempts+1)+"");
							statsMsg.push("DebugLevels");
							statsMsg.push("" + __curDoc__.__fb__.preConnectedDebugLevel + ", " + __curDoc__.__fb__.postConnectedDebugLevel
									  + ", " + __curDoc__.__fb__.postReadyDelay         + ", " + __curDoc__.__fb__.postInstantiationDelay+"");
							__curDoc__.hostContainer.postMessage(statsMsg);
							__curDoc__.__fb__.fbDebugLevel = __curDoc__.__fb__.postConnectedDebugLevel;
						}
						fb_gotMessageFromHtmlHost(arrayOfStrings, this.doc);
						return;
					}

					function fb_HandleErrorFromPostMessage(errorObject, arrayOfStrings)
					{
						__curDoc__ = this.doc;
						fb_processError(errorObject, arrayOfStrings);
						return;
					}

					function fb_DetermineWhetherToDisclose(htmlUrl, pdfUrl)
					{
						__curDoc__ = this.doc;
						return fb_disclosureCheck(htmlUrl, pdfUrl);
					}




					// That's the last of the 'pure communication' part. The rest is 'functionality'.


					function fb_processError(error, arrayOfStrings)
					{
						// Error messages should not be encountered in normal circumstances.
						// If it occurs, it is is most likely reporting a security error
						// This is about errors this PDF has encountered in posting messages to the hos

						fbDebug(0, "PDF: Error of name: '" + error.name + "' during processing of message '" + arrayOfStrings + "'");
						for (var prop in error)
						{
							fbDebug(0, ".. " + prop + ": '" + error[prop] + "'");
						}
						fbDebug(0, "Communication tries: " + __curDoc__.__fb__.communicationInitializationAttempts);
						if (__curDoc__.__fb__.communicationInitializationAttempts <= 50)
						{
							fb_SetupCommunicationsWithTheHostHtml(__curDoc__);
							return;
						}
						if (error.name != "MessageGeneralError")		// this error is not helpful
							app.alert("The PDF has encountered error: '" + error + "':  '" + arrayOfStrings + "'");
					};


					function fb_disclosureCheck(htmlURL, pdfURL)
					{
						// Reader will allow external applications to communicate with the
						// JavaScript contained within the PDF document only if this function returns
						// true.  We will allow the communication only if the URL of the web page
						// trying to communicate with us comes from the same root url as the PDF.

						fbDebug(3, "PDF: Doing onDisclose for an URL that wants to communicate with this PDF");
						fbDebug(3, "  htmlUrl: '" + htmlURL + "'");
						fbDebug(3, "  pdfUrl: '" + pdfURL + "'");

						// Some file URLs have colons which appear as an 'or' bar so we translate those back to colons
						// Note that the replace function does not work on argument variables so we copy them to temporary variables
						var htmlURL2 = htmlURL;
						var pdfURL2  = pdfURL;
						var htmlURL3 = htmlURL2.replace(/\|/g, ":");
						var pdfURL3  = pdfURL2 .replace(/\|/g, ":");
						// Decode the URIs and split them into tokens
						htmlTokens = decodeURI(htmlURL3).split("/");
						pdfTokens  = decodeURI(pdfURL3) .split("/");
						// Normally we compare only the first three tokens e.g. "http:", "" and "server:8080"
						var compareCount = 3;
						if (htmlTokens[0] == "file:") {
							// In the case of files, we compare the common folders
							compareCount = Math.min(htmlTokens.length, pdfTokens.length) - 1;
							compareCount = Math.max(compareCount, 2);
						}

						// All the tokens in the compare count must match exactly
						for (var i=0; i < compareCount; i++) {
							if (htmlTokens[i] != pdfTokens[i]) {
								fbDebug(0, "PDF: OnDisclose test failed:");
								fbDebug(0, "  html:[" + htmlURL + "]");
								fbDebug(0, "  pdf :[" + pdfURL + "]");
								fbDebug(0, "  FAILED (" + i + ") [" + htmlTokens[i] + " vs " + pdfTokens[i] + "].");
								return false;
							}
						}

						fbDebug(3, "  onDisclose has been approved ");
						return true;
					};

					// Well now, that's really the last of the pure communication stuff















/*
    FormBridge provides a scripting API to access and change information in a PDF form.
    It supports actions such as getting and setting form data, getting a list
    of fields, email, and print, just to name a few.
    Messages sent to this script have the following format:
        ["id"]["requestName"]["params..."]				(Strings w/o the quotes)
    where:
        id          is a number supplied by the requestor
        requestName is the command to perform (see: "FormBridge API command"s below)
        params      are the parameters for the command
    The response has the following format:
        [id][requestName][returnId][returnValue]
    where:
        id          is the same number as the request id
        requestName is the same as the original request name
        returnId    is a string indicating success or failure (see: "Return identifiers" below)
        returnValue is the return value of the command (if applicable)
    Command parameters and return values can be simple values are they can be arrays.
    Since the whole messages are passed as arrays, we use special identifiers to indicate
    arrays within arrays (see array identifiers).
	Every array must be an array *of Strings* (and only Strings).
*/

/* Version of the Correspondence Management form bridge interface */
var FORM_BRIDGE_VERSION = "cm1.0";
/* FormBridge API commands */
var R_GET_BRIDGE_VERSION            = "getBridgeVersion";
var R_GET_FORM_TYPE                 = "getFormType";
var R_GET_DATA                      = "getData";
var R_SET_DATA                      = "setData";
var R_GET_SUBMIT_BUTTONS            = "getSubmitButtons";
var R_GET_INDIRECT_SUBMIT_BUTTONS   = "getIndirectSubmitButtons";
var R_GET_ALL_FIELDS                = "getAllFieldNames";
var R_GET_LABELS                    = "getLabels";
var R_GET_LIST_ITEMS                = "getListItems";
var R_GET_SELECTED_ITEM             = "getSelectedItem";
var R_SELECT_LIST_ITEM              = "selectListItem";
var R_HIDE_FIELDS                   = "hideFields";
var R_SHOW_FIELDS                   = "showFields";
var R_EXEC_ACTION                   = "execAction";
var R_EMAIL_ACTION                  = "emailAction";
var R_PRINT_ACTION                  = "printAction";
var R_SAVEAS_ACTION                 = "saveAsAction";
var R_SUBMIT_ACTION                 = "submitAction";
var R_GET_FOCUS                     = "getFocus";
var R_SET_FOCUS                     = "setFocus";
var R_GET_FIELD_VALUE               = "getFieldValue";
var R_SET_FIELD_VALUE               = "setFieldValue";
var R_SET_DATA_FIELDS_LIST          = "setDataFieldsList";
var R_RESOLVE_SOM_PROPERTIES        = "resolveSOMProperties";
var R_SET_SOM_PROPERTIES            = "setSOMProperties";
var R_HAS_SUBMIT_BUTTON             = "hasSubmitButton";
var R_GET_SUBMIT_TYPE             	= "getSubmitType";
/* Return identifiers used in response messages */
var SUCCESS                 = "success";
var E_FAILURE               = "failure";
var E_BAD_PARM              = "badParm";
var E_UNSUPPORTED_MSG       = "unsupportedMsg";
var E_SETDATA_LOADXML       = "E_SETDATA_LOADXML";
/* Specifying the submit url and type here will override the url and type defined in the form */
var BRIDGE_SUBMIT_URL       = null;

var BRIDGE_SUBMIT_TYPE      = null;
var BRIDGE_SUBMIT_TYPE_FIELD      = "AWS_SUBMIT_TYPE";
/* Array identifiers used when passing arrays in incoming and outgoing messages */
var ARRAY_START             = "[--->";
var ARRAY_END               = "<---]";
/* The various click events that can exist for a field */
var clickActivities  = ["click", "mouseUp", "mouseDown"];

/* * * */
/* * * *	Note that this whole script object is reset/reinitialized on every 'form_ready' */
/* * * */
fbDebug(0, "Our script variables were re-initialized");

/* We cache the indirectSubmitButtons so that we retrieve them only once */
var indirectSubmitButtons  = null;
/* We cache the submitButtons so that we retrieve them only once */
var submitButtons = null;
/* Indicator that we have initialized sufficiently to really try and communicate */
/* blocks race condition messages from appearing */
var msgIn				= null;
var outMessage			= null;



function isAnArray(possibleArray)
{
	if (typeof(possibleArray) == "Array") 	return true;
	if (typeof(possibleArray) != "object") 	return false;
	if (typeof(possibleArray.length) != "number") return false;
	if (typeof(possibleArray.push) != "function") return false;
	// Well, it quacks like an array!
	return true;
}
function isAString(possibleString)
{
	return( typeof(possibleString) == "string" );
}


function fbDebug(level, msg)
{
	if (typeof(__curDoc__) == "undefined" || __curDoc__ == null)
	{
		var t = new Date().getTime();
		console.println("(no doc) "+ t + ": " + msg);
		return;
	}

	if (level <= __curDoc__.__fb__.fbDebugLevel)
	{
		if (__curDoc__.__fb__.messageReceived == true)
			__curDoc__.hostContainer.postMessage(["log", ""+level+"", msg]);
		else
			console.println(timeit()+msg);
	}
}
function setDebugLevel_FormBridge(doc, level, p2, p3, p4)
{
	fbDebug(2, "PDF: FormBridge debug level is changing from " + __curDoc__.__fb__.fbDebugLevel + " to " + level);
	__curDoc__.__fb__.fbDebugLevel = level;
	fbDebug(2, "PDF: FormBridge debug level was set to " + __curDoc__.__fb__.fbDebugLevel);
	return (SUCCESS);
}














/* * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * */
/* Handle an incoming message										   */
/* * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * */
// This breaks messages apart into (message id, request, params) and forwards
// the request to the corresponding function.
// It then assembles and sends the response.
// When run: 'this' is the "doc.hostContainer.messageHandler" object
function fb_gotMessageFromHtmlHost(inMessage, doc)
{
	__curDoc__ = doc;
	fbDebug(9, "PDF: gotMessageFromHtmlHost: '" + inMessage + "'");

	if (doc.hostContainer.messageHandler.doc != doc)
	{
		app.alert("PDF: Internal consistency check has failed. The 'doc' value is inconsistent.");
		return;
	}

	if ((""+inMessage+"") == "~ping~")
	{
		doc.hostContainer.postMessage(new Array("~pong~"));
		return;
	}



	// We expect that inMessage is an *array* of *strings*, but  ... things ... happen
	// Arrays that come over the communication channel seem to get messed up.
	// Treat them as objects and re-create an array from the object's properties.
	// Messages posted to the PDF should ALWAYS be Arrays, and arrays of ONLY Strings

	if (isAString(inMessage))
	{
		fbDebug(8, "We received a string-based message (stuffing into an array): " + inMessage);
		msgIn = new Array();
		msgIn.push(inMessage);
	}
	else if (typeof(inMessage) == "object")
	{
		fbDebug(8, "We received an object-based message (and will convert to an array): " + inMessage);
		msgIn = new Array();
		for (var prop in inMessage)
		{
			fbDebug(9, "  '" + prop + "' = '" + inMessage[prop] + "';");
			msgIn.push(""+inMessage[prop]+"");
		}
	}
	fb_processMessage(doc, 1);
}

function fb_processMessage(doc, nTimes)
{
    // Now, process the array-based message
	__curDoc__ = doc;
    var msgId     = msgIn.shift();
    var request   = msgIn.shift();
    var param1    = getParam(msgIn);
    var param2    = getParam(msgIn);
    var param3    = getParam(msgIn);
    var param4    = getParam(msgIn);
    var returnId  = SUCCESS;
    var returnVal = null;
    if ( xfa.host.name != "Flash" ) {
		eval("__fb__doc__ = null;");		// create a real global
		__fb__doc__ = doc;					// save the doc handle in case of thrown error
        // Forward the request to the corresponding function
        try {
            var override = sanitizeRequest(request);
            if ( override != null ) {
				fbDebug(9, "PDF: The message from the host HTML is being turned over to function: '" + request + "_FormBridge'");

				returnVal = eval(request + "_FormBridge(doc, param1, param2, param3, param4);" );
				fbDebug(9, "PDF: That function evaluated to: '" + returnVal + "'");
            } else {
				fbDebug(9, "PDF: The message from the host HTML is being given the normal switch statement treatment");
              switch (request) {
                case R_GET_BRIDGE_VERSION:          returnVal = bridgeVersion();            break;
                case R_GET_FORM_TYPE:               returnVal = formType;                   break;
                case R_GET_DATA:                    returnVal = getData();                  break;
                case R_GET_SUBMIT_BUTTONS:          returnVal = getSubmitButtons();         break;
                case R_GET_INDIRECT_SUBMIT_BUTTONS: returnVal = getIndirectSubmitButtons(); break;
                case R_GET_ALL_FIELDS:              returnVal = getAllFieldNames();         break;
                case R_GET_LABELS:                  returnVal = getLabels(param1);          break;
                case R_GET_LIST_ITEMS:              returnVal = getListItems(param1);       break;
                case R_GET_SELECTED_ITEM:           returnVal = getSelectedItem(param1);    break;
                case R_SELECT_LIST_ITEM:            selectListItem(param1, param2);         break;
                case R_SET_DATA:                    setData(param1);                        break;
                case R_HIDE_FIELDS:                 hideFields(param1);                     break;
                case R_SHOW_FIELDS:                 showFields(param1);                     break;
                case R_EXEC_ACTION:                 execAction(param1);                     break;
                case R_EMAIL_ACTION:                emailAction(doc, param1);               break;
                case R_PRINT_ACTION:                printAction(doc, param1);               break;
                case R_SAVEAS_ACTION:               saveAsAction(doc, param1);              break;
                case R_SUBMIT_ACTION:               submitAction(doc, param1, param2);      break;
                case R_GET_FOCUS:                   returnVal = getFocus();                 break;
                case R_SET_FOCUS:                   setFocus(param1);                       break;
                case R_GET_FIELD_VALUE:             returnVal = getFieldValue(param1);      break;
                case R_SET_FIELD_VALUE:             setFieldValue(param1, param2, param3);  break;
                case R_SET_DATA_FIELDS_LIST:        setDataFieldsList(param1, param2, param3, param4);      break;
                case R_RESOLVE_SOM_PROPERTIES:      returnVal = resolveSOMProperties(param1, param2);       break;
                case R_SET_SOM_PROPERTIES:          returnVal = setSOMProperties(param1, param2, param3);   break;
				case R_HAS_SUBMIT_BUTTON:           returnVal = hasSubmitButton();      	break;
                case R_GET_SUBMIT_TYPE:           	returnVal = getSubmitType();      		break;
                default:                            returnId = E_UNSUPPORTED_MSG;           break;
              }
            }
        } catch(exception) {
            returnId  = E_FAILURE;
            returnVal = exception;
			__curDoc__ = __fb__doc__;	// Restore our doc context, in case context-switching occurred
			doc = __curDoc__;
			fbDebug(0, "PDF: Trying to process request '" + request + "' from the host HTML has caused an exception");
			fbDebug(0, "PDF: Exception: '" + returnVal + "'");
        }
		__curDoc__ = __fb__doc__;	// Restore our doc context
		doc = __curDoc__;
		fbDebug(9, "PDF: The return code from processing the '" + request + "' request is: '" + returnId + "'");
		// Just being over-sure here. We're processing a request! We must have established communication.
		fb_clearTimeout();

		// No response to the HTML host is desired for successful EXEC or SUBMIT actions
		if (returnId == SUCCESS) {
			if (request == R_EXEC_ACTION  || request == R_SUBMIT_ACTION)
			{
				fbDebug(9, "PDF: Deliberately not providing a response for successful request: " + request);
				return;
			}
		}


		// Otherwise we want to tell the HTML host all about it
        {
			if (returnVal == null)
			{
				;
			}
			else if (isAnArray(returnVal))
			{
				;
			}
			else if (isAString(returnVal))
				;
			else {
				fbDebug(9, "PDF: The return value is of type " + typeof(returnval));
				fbDebug(9, "PDF: That value is '" + returnVal + "'");
			}
			postResultBackToHtmlHost(doc, msgId, request, returnId, returnVal);
        }
    }
}

// Internal Helper function to communicate results back to the host HTML -- always as an array
function postResultBackToHtmlHost(doc, msgId, request, returnId, returnVal)
{
    outMessage = new Array();
    outMessage.push(""+msgId+"");
    outMessage.push(request);
    outMessage.push(returnId);
    if (returnVal != null)
	{
        // include array delimiters, if any, in the response
        if (isAnArray(returnVal))
		{
            outMessage.push(ARRAY_START);
            for (var i=0; i < returnVal.length; i++)
			{
				if (isAnArray(returnVal[i]))
					fbDebug(7, "PDF: An array item *inside* the return value has been pushed directly into the array being returned: " + i);
                outMessage.push(returnVal[i]);
            }
            outMessage.push(ARRAY_END);
        } else {
            outMessage.push(""+returnVal+"");
        }
    }
	fbDebug(8, "PDF: The assembled response array is: '" + outMessage + "'");
	for (var prop in outMessage)
	{
		fbDebug(9, "PDF: '" + prop + "' = '" + outMessage[prop] + "'");
		if (! isAString(outMessage[prop]))
			fbDebug(9, "PDF: '" + prop + "' is not a String but a/an " + typeof(outMessage[prop]));
	}
    __curDoc__.hostContainer.postMessage(outMessage);
}



/**
 * This is a utility function for 'parsing' the incoming messages (requests)
 *   Incoming message requests are arrays which may have content as follows:
 *	    x  y  z {ARRAY_START} a b c {ARRAY_END} 1 2 3
 *	 This routine treats that as 7 parameters: x, y, z, [a,b,c], 1, 2, 3
 *   The parameter may be an array; if so, this function removes the
 *   array delimiters and returns its contents as a single array-type object.
 */
function getParam(inMsg) {
    if (inMsg.length == 0) {
        return null;
    }
    // If the parameter is not an array, simply return its value
    var param = inMsg.shift();
    if (param != ARRAY_START) {
        return param;
    }
    // Create a new array and copy the values into it
    param = new Array();
    while (inMsg.length > 0 && inMsg[0]!=ARRAY_END) {
        param.push(""+inMsg.shift()+"");
    }
    // Get rid of the ARRAY_END delimiter
    if (inMsg.length != 0) {
        inMsg.shift();
    }
    return param;
}

/* This function is used to make sure the function request sent in is just a name 			*/
/* and not some actual executable from-the-wild code, and also that that function exists. 	*/
/* We need to neutralize the sending in of actual code since we do actually 'eval(...)' it.	*/
/* Only functions that have been added to this script are allowed.							*/
function sanitizeRequest(request) {
    if ( request.indexOf("{") >= 0 )
        return null;
    else if ( request.indexOf("(") >= 0 )
        return null;
    else if ( request.indexOf(" ") >= 0 )
        return null;

    try {
        var ret = eval( "typeof( " + request + "_FormBridge )" );
        if ( ret != "function" ) {
            request = null;
        }
    } catch(exception) {
        request = null;
    }
    return request;
}

/* This function allows JavaScript code in the PDF to call out to the host */
var sendMsgId = 0;
function postToFormBridge(doc, request, data, callback) {
    if (callback == null ) callback = SUCCESS;
    postToFormBridgeInternal(doc, sendMsgId++, request, callback, data);
}
/* * * * * * The Form Bridge plumbing is over! On to actual request handling * * * * * * */




/****************************************************************************/
/*      Handlers for Request messages                                       */
/****************************************************************************/
/* Return the Form Bridge version */
function bridgeVersion(){
    return FORM_BRIDGE_VERSION;
}
/** Extract the form data and remove the newlines */
function getData() {
    // Pad out the response to fix the Firefox 3.5.x 'off by one issue'.
    return xfa.datasets.saveXML() + "\n";
}
/** Set the data dom with the passed data */
function setData(data) {
    var xfaData = data;

    // For certain forms XFA will not allow updates to the entire datasets so the data only portion
    // must be extracted.
    // The XML passed in can come in different flavours that have to be massaged in order to get XFA to accept
    // the data.

    // Check for standard <xfa:data> first
    var searchFor = "xfa:data";
    var xfaDataStart = data.indexOf("<" + searchFor, 50); // Start past the ever present <xfa:datasets tag
    var xfaDataEnd   = 0;
    if ( xfaDataStart >= 0 ) {
        xfaDataEnd = data.indexOf("</" + searchFor, xfaDataStart);
        var xfaNS = (data.indexOf("xmlns:xfa", xfaDataStart) < 0)?"xmlns:xfa=\"http://www.xfa.org/schema/xfa-data/1.0/\"":"";
        xfaData    =  "<xfa:data " + xfaNS
                        + data.substring(xfaDataStart + searchFor.length + 1, xfaDataEnd)
                    + "</xfa:data>";
    } else {  // Did not find <xfa:data; Check for user defined <data> second
        searchFor = "data";
        xfaDataStart = data.indexOf("<" + searchFor, 0);
        if ( xfaDataStart >= 0 ) {
            var i = xfaDataStart;
            while (i >= 0) { // Find the *last* </data
                xfaDataEnd = i;
                i = data.indexOf("</" + searchFor, i+1);
            }
            xfaData = "<" + searchFor + data.substring(xfaDataStart + searchFor.length + 1, xfaDataEnd) + "</" + searchFor + ">";

            // Have to remove the "FORMSERVER" variables as well as their enclosing <root>..</root>
            // since loadXML will fail if they are left in
            var i = xfaData.search( /<(FS[A-Z]+)_\s*\/?>/ ); // Any <FSXXXX_ [/]> tags?
            if (i >= 0) {
                xfaData = xfaData.replace( /<(FS[A-Z]+)_\s*>.*<\/\1_\s*>\s*/g   ,   "" );
                xfaData = xfaData.replace( /<(FS[A-Z]+)_\s*\/>\s*/g             ,   "" );
                xfaData = xfaData.replace( /<root\s*>\s*<\/root\s*>\s*/g        ,   "" );
                xfaData = xfaData.replace( /<root\s*\/>\s*/g                    ,   "" );
            }
        }
    }


    try {
        // Call XFA to load the sanitized data and force a remerge
        xfa.datasets.data.loadXML(xfaData, 1, 1);
    } catch (err)   {
        throw E_SETDATA_LOADXML + ": " + err;
    }
    xfa.form.remerge();

    // perform a relayout, in case there is a need (due to data based layout changes)
    xfa.layout.relayout();
    xfa.layout.relayout();

    // app.runtimeHighlight = false; // remove PDF highlight on fields
}
/**
 * Retrieve the value associated with a single form field.
 *
 * @param somExpression Full path to the XML data node.
 */
function getFieldValue(somExpression)
{
    var field = xfa.form.resolveNode(somExpression);
    if ( field != null )
        return field.rawValue;
    else
        return "";
}
/**
 * Set the XML value associated with a single form field.
 *
 * @param somExpression Full path to the XML data node.
 * @param new Value Replacement value for the XML data node.
 */
function setFieldValue(somExpression, type, newValue)
{
    setFieldValue2(somExpression, type, newValue, true)
}
/**
 * Set the XML value associated with a single form field, with optional remerge.
 *
 * @param somExpression Full path to the XML data node.
 * @param new Value Replacement value for the XML data node.
 */
function setFieldValue2(somExpression, type, newValue, remerge)
{
    var field = xfa.form.resolveNode(somExpression);
    if ( field != null ) {
        switch (type) {
            case "booleanValue":
            case "selected":
            case "selectedItems":
            case "dateValue":
            case "rawValue":
            default:
                var i = 0;
                if (newValue.indexOf("<exData") == 0)
                {
                    var i = newValue.indexOf("<", 2);
                    var j = newValue.indexOf("</exData>");
                    newValue = newValue.substring(i, j-1); // Strip off the <exdata> enclosure
                    i = 1;
                }
                else if (newValue.indexOf("<body") == 0)
                    i = 1;
                else if (newValue.indexOf("<P") == 0)
                    i = 1;
                else if (newValue.indexOf("<p") == 0)
                    i = 1;
                if (i == 1) {
                    try {
                        field.value.exData.loadXML(newValue, 0, 1);
                    } catch (err) {
                        field.rawValue = newValue;
                    }
                }
                else
                {
                    field.rawValue = newValue;
                }
        }
        if ( remerge ) {
            xfa.datasets.saveXML();
            xfa.form.remerge();
        }
    }
}
/* Set the values for the fields in the list as well as sync the subform occurs information */
function setDataFieldsList(subforms, occurs, fields, values) {
    var i;
    var allowRemerge = true;
    // Step through each subform's instances and set their occurrences
    for (i=0; i < subforms.length; i++) {
        var subform = resolveFormNode(subforms[i]);
        if ( subform != null ) {
            try {
                // Call XFA to load the subform instance data but fail silently and continue if it can't.
                subform.setInstances(occurs[i]);
            } catch (err)   {
                ;
            }
        }
    }
    // Step through the fields and set their values
    for (i=0; i < fields.length; i++) {
        try {
            // Call XFA to load the field data but fail silently and continue if we can't resolve the field's node,
            // also don't update signature fields.
            var sigfield = resolveNode(fields[i] + ".ui.signature");
            if ( sigfield == null ) {
                // check to make sure the field is not locked by a signature.
                var properties = new Array();
                properties.push("locked");
                var properties = resolveSOMProperties(fields[i], properties);
                if ( properties[1] == "locked:locked" ) {
                    allowRemerge = false;
                } else {
                    setFieldValue2(fields[i], null, values[i], false);
                }
            }
        } catch (err) {
            ;
        }
    }
    if ( allowRemerge ) {
        xfa.datasets.saveXML();
        xfa.form.remerge();
    }
}
/** Get the submit actions. Returns an array of som expressions */
function getSubmitButtons() {
    if (submitButtons != null) {
        return submitButtons;
    }
    var allFields           = getAllFields();
    var buttons             = getButtons(allFields);
    var directSubmitButtons = getDirectSubmitButtons(buttons);
    var allButtons          = getAllSubmitButtons(buttons, directSubmitButtons);
    submitButtons           = toSOMs(allButtons);
    return submitButtons;
}
/** Get the indirect submit actions. Returns an array of som expressions */
function getIndirectSubmitButtons() {
    if (indirectSubmitButtons != null) {
        return indirectSubmitButtons;
    }
    var allFields           = getAllFields();
    var buttons             = getButtons(allFields);
    var directSubmitButtons = getDirectSubmitButtons(buttons);
    var allButtons          = getAllIndirectSubmitButtons(buttons, directSubmitButtons);
    indirectSubmitButtons   = toSOMs(allButtons);
    return indirectSubmitButtons;
}
/** Return all of the field names in the form */
function getAllFieldNames() {
    var fieldSOMs = new Array();
    for (var page=0; page < xfa.layout.absPageCount(); page++) {
        var fields = xfa.layout.pageContent(page, "field");
        for (var i=0; i < fields.length; i++) {
            var som = fields.item(i).somExpression;
            som = som.replace(/\[0\]/g, "");
            som = som.replace(/xfa.form./g, "");
            som = som.replace(/#subform./g, "");
            fieldSOMs[i] = som;
        }
    }
    return fieldSOMs;
}
/** Return the labels for the supplied list of fields */
function getLabels(fields) {
    var names = new Array();
    for (var i=0; i < fields.length; i++) {
        var field = resolveFormNode(fields[i]);
        names.push(field.caption.value.text.value);
    }
    return names;
}
/* Return the list items for a list field */
function getListItems(fieldName) {
    var listItems = new Array();
    var items = xfa.resolveNodes("$form.." + fieldName + ".#items.#text[*]");
    for (var i=0; i < items.length; i++) {
        listItems.push(items.item(i).value);
    }
    return listItems;
}
/** Get the selected item in a list field */
function getSelectedItem(fieldName) {
    var list = resolveFormNode(fieldName);
    return list.rawValue;
}
/* Select a list item of a list field */
function selectListItem(fieldName, listItem) {
    var list = resolveFormNode(fieldName);
    list.rawValue = listItem;
}
/* Hide the fields in the supplied list of fields */
function hideFields(fields) {
    for (var i=0; i < fields.length; i++) {
        var field = resolveFormNode(fields[i]);
        if(field.presence=="visible"){
               field.presence="invisible";
        }
    }
}
/* Show the fields in the supplied list of fields */
function showFields(fields) {
    for (var i=0; i < fields.length; i++) {
        var field = resolveFormNode(fields[i]);
        field.presence="visible";
    }
}
/** Execute an action e.g. click */
function execAction(buttonName) {
    var button = resolveFormNode(buttonName);
    if (button != null) {
        var event = getClickEvent(button);
        if (event != null) {
            setFocus(null);  // force current field focus out in 8.1 + readers (null op in previous versions)
            button.execEvent(event.activity);
        }
    }
}
/** Invoke the standard Email action */
function emailAction(doc, param1) {
    doc.mailDoc(true, "");
}
/** Invoke the standard Print action */
function printAction(doc, param1) {
    app.execMenuItem("Print", doc);
}
/** Invoke the standard SaveAs action */
function saveAsAction(doc, defaultFile) {
    doc.documentFileName = defaultFile;
    app.execMenuItem("SaveAs", doc);
}
/** Invoke the standard Submit action */
function submitAction(doc, url, type) {
    if ( BRIDGE_SUBMIT_URL  != null ) url  = BRIDGE_SUBMIT_URL;
    if ( BRIDGE_SUBMIT_TYPE != null ) type = BRIDGE_SUBMIT_TYPE;
    if ( type == null ) type = "PDF";
    if (url != null) {
        setFocus(null);  // force current field focus out in 8.1 + readers (null op in previous versions)
//      doc.submitForm({cURL: url, bEmpty: true, cSubmitAs: type, cCharset: "utf-8"});
        doc.submitForm({cURL: url, cSubmitAs: type});
    }
}
/** Get the focus from XFA  */
function getFocus() {
    if ( xfa.host.getFocus )
        return xfa.host.getFocus().somExpression;
    else
        return "unsupported";
}
/** Set the focus in XFA  */
function setFocus(som) {
    if ( xfa.host.setFocus ) {
        if ( som == null ) {
            if ( xfa.host.appType == "Reader" || xfa.host.name == "Acrobat" ) {
                if ( xfa.host.version >= "8.1" ) {
                    xfa.host.setFocus(som);
                }
            }
        } else {
            xfa.host.setFocus(som);
        }
    }
}
/**
 * Retrieve the list of value(s) associated with properties of the SOM object.
 *
 * @param somExpression Full pathway to the XML node.
 */
function resolveSOMProperties(somExpression, properties)
{
    var values = new Array();
    var value;
    values.push( "som:" + somExpression );
    var obj = resolveFormNode(somExpression);
    if ( obj != null ) {
        for (var i=0; i < properties.length; i++) {
            if ( properties[i] == "objectXml" ) {
                value = obj.saveXML();
            } else if ( properties[i] == "object" ) {
                value = obj;
            } else if ( properties[i] == "locked" ) {
                var locked = "open";
                if ( obj.access == "readOnly" ) {
                try {
                    obj.access = "open";
                    } catch (err)   {
                        ;
                    }
                    if ( obj.access == "readOnly" ) {
                        locked = "locked";
                    } else {
                        obj.access = "readOnly";
                    }
                }
                value = locked;
            } else {
                value = obj.getAttribute( properties[i] );
            }
            values.push( (properties[i] + ":" + value) ) ;
        }
    }
    return values;
}
/**
 * Set the list of value(s) associated with properties supplied for the SOM object.
 *
 * @param somExpression Full path to the XML node.
 */
function setSOMProperties(somExpression, properties, values)
{
    var obj = resolveFormNode(somExpression);
    var ret = true;
    if ( obj != null ) {
        for (var i=0; i < properties.length; i++) {
            if ( properties[i] == "objectXml" ) {
                obj.loadXML(values[i], 1, 1);
            } else if ( properties[i] == "object" ) {
                obj = values[i];
            } else {
                obj.setAttribute( values[i], properties[i] );
            }
        }
    }
    return ret;
}
/******************************************************************************/
/*      Utility functions                                                     */
/******************************************************************************/
/** Convenience function for resolving a form node with 2 additional levels of resolution */
function resolveFormNode(fieldName) {
    var formNode = null;
    if(fieldName!= null && (""+fieldName).indexOf("xfa[0].datasets[0].data[0]") > -1)
        formNode = xfa.resolveNode(fieldName);
    else
        formNode = xfa.resolveNode("$form.." + fieldName);
    if ( formNode == null && fieldName.indexOf(".") > 0 ) {
        fieldName = fieldName.substr(fieldName.indexOf(".")+1);
        formNode  = xfa.resolveNode("$form.." + fieldName);
        if ( formNode == null && fieldName.indexOf(".") > 0 ) {
            fieldName = fieldName.substr(fieldName.indexOf(".")+1);
            formNode  = xfa.resolveNode("$form.." + fieldName);
        }
    }
    return formNode;
}
/** Return all of the fields in the form */
function getAllFields() {
    var allFields = new Array();
    for (var page=0; page < xfa.layout.absPageCount(); page++) {
        var pageFields = xfa.layout.pageContent(page, "field");
        for (var i=0; i < pageFields.length; i++) {
            allFields.push(pageFields.item(i));
        }
    }
    return allFields;
}
/** Create an array of field SOM expressions */
function toSOMs(fields) {
    var fieldSOMs = new Array();
    for (var i=0; i < fields.length; i++) {
        var som = fields[i].somExpression;
        som = som.replace(    /^xfa(\[.\])?\./g, "");
        som = som.replace(   /^form(\[.\])?\./g, "");
        som = som.replace(/#subform(\[0\])?\./g, "");
        som = som.replace(/\[0\]/g, "");
        fieldSOMs.push(som);
    }
    return fieldSOMs;
}
/** Return the buttons in the passed field array */
function getButtons(fields) {
        var buttons = new Array();
    var field;
    var sUIClassName;
    for (var i=0; i < fields.length; i++) {
        field = fields[i];

        sUIClassName = field.ui.oneOfChild.className;
        if (sUIClassName == "button")
        {
            buttons.push(field);
        }
    }
    return buttons;
}
/** Return the visible buttons in the passed field array */
function getVisibleButtons(buttons) {
    var visibleButtons = new Array();
    for (var i=0; i < buttons.length; i++) {
        var button = buttons[i];
        if (button.presence!="invisible" && button.presence!="hidden") {
            visibleButtons.push(button);
        }
    }
    return visibleButtons;
}
/** Return the direct submit buttons in the passed buttons array */
function getDirectSubmitButtons(buttons) {
    var direct = new Array();
    for (var i=0; i < buttons.length; i++) {
        var button = buttons[i];
        if (getSubmitEvent(button) != null) {
            direct.push(button);
        }
    }
    return direct;
}
/** Return the submit event, if any, for this button */
function getSubmitEvent(button) {
    var event = getClickEvent(button);
    if (event!=null && isSubmitEvent(event)) {
        return event;
    }
    return null;
}
/** Return the Click/MouseUp/MouseDown event, if any, for this button */
function getClickEvent(button) {
    var events = xfa.resolveNodes(button.somExpression + ".#event[*]");
    for (var i=0; i < clickActivities.length; i++) {
        var event = getEvent(events, clickActivities[i]);
        if (event!=null) {
            return event;
        }
    }
    return null;
}
/** Find the event handling a certain activity */
function getEvent(events, activity) {
    for (var i=0; i < events.length; i++) {
        if (events.item(i).activity == activity) {
            return events.item(i);
        }
    }
    return null;
}
/** Return true if the event is a submit event */
function isSubmitEvent(event) {
    var sEventClassName = event.oneOfChild.className;
    if (sEventClassName == "submit")
    {
        return true;
    }

    if (sEventClassName == "script")
    {
        var script = event.script.value;
        if (script.indexOf(".exportData")!=-1)
        {
            return true;
        }
    }

    return false;
}
/** Return all direct submit buttons */
function getAllSubmitButtons(visibleButtons, directSubmitButtons) {
    var allButtons = new Array();
    for (var i=0; i < visibleButtons.length; i++) {
        var button = visibleButtons[i];
        if (contains(button, directSubmitButtons)) {
            if ( !repeatableParent(button) ) {
                allButtons.push(button);
            }
        }
    }
    return allButtons;
}
/** Return all indirect submit buttons */
function getAllIndirectSubmitButtons(visibleButtons, directSubmitButtons) {
    var allButtons = new Array();
    for (var i=0; i < visibleButtons.length; i++) {
        var button = visibleButtons[i];
        // check for indirect submit references */
        var indirect = getIndirectSubmitButton(button, directSubmitButtons);
        if (indirect != null) {
            if ( !repeatableParent(indirect) ) {
                allButtons.push(indirect);
            }
        }

    }
    return allButtons;
}
/** Return the submit event, if any, for this button */
function getIndirectSubmitButton(button, directSubmitButtons) {
    var events = xfa.resolveNodes(button.somExpression + ".#event[*]");
    for (var i=0; i < clickActivities.length; i++) {
        var event = getEvent(events, clickActivities[i]);
        if (event!=null && isIndirectSubmitEvent(event, directSubmitButtons)) {
            return button;
        }
    }
    return null;
}
/** Return true if the event is an indirect submit event */
function isIndirectSubmitEvent(event, directSubmitButtons) {
    var sEventClassName = event.oneOfChild.className;

    if (sEventClassName == "script") {
        var script =  event.script.value;
        for (var i=0; i < directSubmitButtons.length; i++) {
            var button = directSubmitButtons[i];
            if (script.indexOf(button.name + ".execEvent") != -1) {

                return true;
            }
        }
    }
    return false;
}
/** Return true if the the item is contained in the array */
function contains(item, array) {
    for (var i=0; i < array.length; i++) {
        if (item === array[i]) {
            return true;
        }
    }
    return false;
}
/** Return true if any parent object has a max occurs value greater than 1 */
function repeatableParent(obj) {
    var repeatable = false;
    while (obj.parent != null) {
        if ( obj.parent.className == "subform" || obj.parent.className == "subformSet" ) {
            if (obj.parent.occur.max == -1 || obj.parent.occur.max > 1) {
                repeatable = true;
                break;
            }
        }
        obj = obj.parent;
    }
    return repeatable;
}
/** Return true if there are submit buttons on the form */
function hasSubmitButton() {
    var allFields               = getAllFields();
    var buttons                 = getButtons(allFields);
    var directSubmitButtons     = getDirectSubmitButtons(buttons);

    var allButtons = new Array();
    for (var i=0; i < buttons.length; i++) {
        var button = buttons[i];
        if (contains(button, directSubmitButtons)) {
            return true;
        }
    }

    for (var i=0; i < buttons.length; i++) {
        var button = buttons[i];
        // check for indirect submit references */
        var indirect = getIndirectSubmitButton(button, directSubmitButtons);
        if (indirect != null) {
            return true;
        }

    }
    return false;
}

/**
 * Pushes to the host the currently selected Content.
 *
 * @param currentContent.
 */
function pushSelectedContent(currentContent)
{
	if (__curDoc__.hostContainer)
		postResultBackToHtmlHost(null, "0", "pushSelectedContent", SUCCESS, currentContent);
}

function getSubmitType()
{
    var submitType = null;
    submitType = getFieldValue("$form.." + BRIDGE_SUBMIT_TYPE_FIELD);
    if (submitType == null || submitType == "")
    {
        var allFields               = getAllFields();
        var buttons                 = getButtons(allFields);
        var directSubmitButtons     = getDirectSubmitButtons(buttons);
        if (directSubmitButtons && directSubmitButtons.length == 1)
        {
            var event = getClickEvent(directSubmitButtons[0]);
            if (event && event.submit)
                submitType = event.submit.format;
            else
                submitType = "UNKNOWN";
        }
        else {
            submitType = "UNKNOWN";
        }
    }

    return submitType;

}

