/**
 * Adobe LiveCycle ICC JavaScript Library for Correspondence Template PDFs
 */

//////////////////////////////////////////////
// Library Constants (always ALLCAPS; private constants start with '_')
//

/** number: The version of the ICC Library. */
var ICC_LIB_VERSION = 1.0;

//////////////////////////////////////////////
// Library Class Constructors (always start with capital and end with 'Class')
//

/**
 * Constructor for a Utility class that offers various utility functions.
 * @return UtilClass Util class instance.
 */
function UtilClass()
{
	/**
	 * Determines the object's type. This is an extension to the typeof operator which knows how to identify XFA form objects and Arrays vs regular
	 *  JavaScript objects.
	 * @param obj The object to test.
	 * @return The six possible values that typeof returns ("number", "string", "boolean", "object", "function", and "undefined") plus "XFAObject" if
	 *  obj is an XFA form object, or "array" if obj is an Array.
	 */
	this.objType = function(obj)
	{
		if (obj == null)
			return "undefined";

		var type = typeof(obj);

		if (type == "object")
		{
			if (obj.toString().indexOf("XFAObject") >= 0)
				type = "XFAObject";
			else if ("length" in obj)
				type = "array";
		}

		return type;
	};
} // end: UtilClass

/**
 * Constructor for a Context class that offers information about the current environment in which this library is running.
 * @return ContextClass Context class instance.
 */
function ContextClass()
{
	//
	// Constants
	//

	//
	// Properties
	//

	//
	// Methods
	//

	/**
	 * Determines if this code is executing within the context of a Form Guide (client-side render).
	 * One of the main uses for this function is to control the code that gets executed while running within the Guided Activities
	 *  (Form Guide Runtime) context where, for example, the "ui.oneOfChild" accessor is not supported on a form object.
	 * @return boolean True if running under Flash; false otherwise.
	 */
	this.isFlex = function() { return (xfa.host.name == "Flash"); };

	/**
	 * @return boolean True if this code is executing within the context of Acrobat/Reader (client-side render).
	 */
	this.isReader = function() { return (xfa.host.name == "Acrobat"); };

	/**
	 * @return boolean True if this code is executing within the context of LiveCycle Forms (server-side render).
	 */
	this.isServer = function() { return (xfa.host.name == "XFAPresentationAgent"); };

	/**
	 * Returns an array where each element represents a part of the current host's version. For example, if the host is the Form Guide and the
	 *  version is "1.0", the array will have two elements, [0] = "1", [1] = "0". If it's "8.1.2.1", the array will be ["8","2","1","2"].
	 * @return array The version array or null if the version couldn't be determined.
	 */
	this.hostVersion = function()
	{
		// if the context is the Form Guide, returns the GA Client Runtime version; if it's Acrobat/Reader, returns the Acrobat/Reader version

		var version = xfa.host.version;
		var verArray = version ? version.split(".") : null;

		return verArray;
	};

} // end: ContextClass()

/**
 * Constructor for Debug class that offers tools for debugging ICC forms.
 * @param ContextClass context Context class instance reference.
 * @param UtilClass util Util class instance reference.
 * @return DebugClass Debug class instance.
 * @throws Error Invalid context and/or util parameter.
 */
function DebugClass(context, util)
{
	if (!context || !util)
		throw new Error("invalid context and/or util parameter!");

	//
	// Constants
	//

	/**
	 * @private
	 * Identifies a null object value in debug output.
	 */
	this._NULL = "_null";

	/**
	 * @private
	 * Identifies an empty string in debug output.
	 */
	this._EMPTYSTR = "_empty";

	/** Informational message severity. */
	this.SEVERITY_INFO = 1;
	/** Warning message severity. */
	this.SEVERITY_WARNING = 2;
	/** Error message severity. */
	this.SEVERITY_ERROR = 3;

	/**
	 * @private
	 * Debug output message prefix.
	 */
	this._PREFIX = "{icc}";

	//
	// Properties
	//

	/**
	 * @private
	 * boolean True if output is visible; false if not. Null initially so we know to look for the special debug form variable.
	 */
	this._showOutput = null;

	/**
	 * @private
	 * Current library context providing information about the script environment.
	 */
	this._context = context;

	/**
	 * @private
	 * Utilities.
	 */
	this._util = util;

	//
	// Methods
	//

	/**
	 * @private
	 * Determines the output for the specified error.
	 * @param Error error Error object whose properties are to be output.
	 * @return string The complete error output string.
	 */
	this._getErrorOutput = function(error)
	{
		if (!error || this._util.objType(error) != "object")
			return "";

		var output = "";
		for (var prop in error)
			output += "\n\t" + prop + ": " + error[prop];

		return output;
	};

	/**
	 * @private
	 * Getter for outputVisible property.
	 * @return boolean True if output should be visible; false otherwise.
	 */
	this._outputVisibleGetter = function()
	{
		if (this._context.isServer())
			return false; // never show on the server

		if (this._util.objType(this._showOutput) == "boolean")
			return this._showOutput;

		// on first access, look for the special icc form variable so that we only resolve it once

		var debugVar = xfa.form.resolveNode("#subform[0].#variables.iccShowDebugOutput");
		if (debugVar != null)
		{
			var show = parseInt(debugVar.value);
			this._showOutput = (!isNaN(show) && show > 0);
		}
		else
			this._showOutput = false;

		return this._showOutput;
	};

	/**
	 * @private
	 * Setter for outputVisible property.
	 * @param boolean visible True if output should be visible; false otherwise.
	 */
	this._outputVisibleSetter = function(visible)
	{
		this._showOutput = (visible == true);
	};

	/**
	 * Get/set if debug output is visible.
	 * Get: On the first call, the function will attempt to read the level specified in the special
	 *  'iccShowDebugOutput' form variable (at the root subform level). If found and its value is
	 *  greater than 0 (zero), debug output will be displayed by default. Otherwise, debug output will
	 *  not be visible by default. Note that the form variable's value will be sought only once. To show
	 *  debug output after initialization, use the showOutput() method.
	 * @param boolean visible If specified, sets whether debug output should be visible.
	 * @return mixed
	 *  void if visible is specified.
	 *  boolean if no parameter is specified: true if debug output should be visible; false if not.
	 */
	this.outputVisible = function() // visible
	{
		if (arguments.length == 1)
		{
			this._outputVisibleSetter(arguments[0]);
			return;
		}

		return this._outputVisibleGetter();
	};

	/**
	 * Output the specified string to Acrobat's JavaScript console.
	 * @param number severity One of the SEVERITY* constant values.
	 * @param string message The message to output.
	 * @return string The complete message output to the console regardless of whether output is visible or not.
	 */
	this.out = function(severity, message)
	{
		var output = this._PREFIX + " ";
		var postfix = " > ";

		switch (severity)
		{
			case this.SEVERITY_WARNING:
				output += "warning";
				break;

			case this.SEVERITY_ERROR:
				output += "ERROR  ";
				break;

			case this.SEVERITY_INFO:
			default:
				output += "info   ";
				break;
		}

		output += postfix + message;

		if (this.outputVisible())
			console.println(output);

		return output;
	};

	/**
	 * Convenience method for info-level outout.
	 * @param string message The output message.
	 * @return string The complete message output to the console regardless of whether output is visible or not.
	 */
	this.info = function(message) { return this.out(this.SEVERITY_INFO, message); };

	/**
	 * Convenience method for warning-level outout.
	 * @param string message The output message.
	 * @return string The complete message output to the console regardless of whether output is visible or not.
	 */
	this.warning = function(message) { return this.out(this.SEVERITY_WARNING, message); };

	/**
	 * Convenience method for error-level outout.
	 * @param string message The output message.
	 * @param Error exception Optional. Error object associated with the error message. If specified, all of its
	 *  properties and associated values will be output immediately after the message.
	 * @return string The complete message output to the console regardless of whether output is visible or not.
	 */
	this.error = function(message) // , exception
	{
		var exception = null;
		if (arguments.length >= 2 && this._util.objType(arguments[1]) == "object")
			exception = arguments[1];

		return this.out(this.SEVERITY_ERROR, message + this._getErrorOutput(exception));
	};

	/**
	 * Recursively dumps the properties and values of an object if outputVisible() is true.
	 * WARNING: You should be careful what the value of each property is. If it contains an object (property value type is "object"),
	 *  the function will recurse into that object's properties and so on. Depending on the type of object it is, this could go on for
	 *  a very long time (e.g. if object property values are form object references, the recursion will go on "forever" and Acrobat will
	 *  look like it has hung).
	 * @param string debugName Debug name of the object being dumped.
	 * @param number severity One of the SEVERITY* constant values.
	 * @param object obj The object being dumped.
	 * @param number padLevel Internal/Optional. The current pad level.
	 * @return string The complete message output to the console regardless of whether output is visible or not.
	 */
	this.dump = function(debugName, severity, obj) //, padLevel
	{
		var output = "";

		if (!debugName)
			return output;

		var bullet = "--";
		var padLevel = 1;

		if (arguments.length >= 4 && this._util.objType(arguments[3]) == "number")
			padLevel = arguments[3];

		if (padLevel == 1)
			output += this.out(severity, "object dump for '" + debugName + "':");

		var pad = "";

		// build the pad according to the pad level
		for (var i = 0; i < padLevel; i++)
			pad += bullet;

		if (obj != null)
		{
			for (var prop in obj)
			{
				var objType = this._util.objType(obj[prop]);
				if (obj[prop] && (objType == "array" || objType == "object"))
				{
					output += "\n\t" + pad + " " + prop + ": [object" + (objType == "array" ? (":" + obj[prop].length) : "") + "]";
					output += this.dump(debugName, severity, obj[prop], padLevel + 1); // recursive call with extra pad level param
				}
				else
					output += "\n\t" + pad + " " + prop + ": " + (obj[prop] ? obj[prop] : (obj[prop] == "" ? this._EMPTYSTR : this._NULL));
			}
		}
		else
			output += "\n\t" + pad + " object is " + (obj == "" ? this._EMPTYSTR : this._NULL);

		if (this.outputVisible() && padLevel == 1)
			console.println(output);

		return output;
	};

} // end: DebugClass

/**
 * Constructor for a Units class that offers methods for working with XFA measurements.
 * @param UtilClass util Util class instance reference.
 * @param DebugClass debug Debug class instance reference.
 * @return UnitsClass Units class instance.
 * @throws Error Invalid util and/or debug parameter.
 */
function UnitsClass(util, debug)
{
	if (!util || !debug)
		throw new Error("invalid util and/or debug parameter!");

	//
	// Constants
	//

	// XFA measurement unit types, per XFA 2.8 spec.

	/** Millimeters. */
	this.MM = "mm";
	/** Centimeters. */
	this.CM = "cm";
	/** Inches. */
	this.IN = "in"; // exactly 2.54cm
	/** Points. */
	this.PT = "pt"; // exactly 1/72in
	/** Default units: Inches. */
	this.DEFAULT = this.IN;

	//
	// Properties
	//

	/**
	 * @private
	 * Utilities.
	 */
	this._util = util;

	/**
	 * @private
	 * Debug.
	 */
	this._debug = debug;

	//
	// Methods
	//

	/**
	 * Determines the numeric value from the qualified value.
	 * @param string qValue Measurement whose value is to be extracted.
	 * @param string toUnits Optional XFAUNIT* const which specifies the conversion units if qValue should be converted to another
	 *  unit before its value is returned.
	 * @return float The numeric value within the unit qualifier.
	 */
	this.val = function(qValue) // , toUnits
	{
		var qConverted = qValue;
		if (arguments.length >= 2)
			qConverted = this.convert(qValue, null, arguments[1]);

		return parseFloat(qConverted);
	};

	/**
	 * Returns the numeric value of the qualified value converted to mm.
	 * @param string qValue Qualified value to convert.
	 * @return float Result from conversion of qualified value to mm.
	 */
	this.valMM = function(qValue)
	{
		return this.val(qValue, this.MM);
	};

	/**
	 * Returns a mm measurement string based on the specified value.
	 * @param mixed value If number, assumes it's mm and returns the qualified value. If it's a string,
	 *  assumes it's a qualified value that may need to be converts to mm.
	 * @return string Measurement in mm (possibly converted). If value is invalid, returns '0mm'.
	 */
	this.outMM = function(value)
	{
		var type = this._util.objType(value);
		if (type == "number")
			return value.toString() + this.MM;
		else if (type == "string")
			return this.val(value, this.MM).toString() + this.MM;
		else
			this._debug.warning("Units.outMM -- specified value has unknown type: output is 0mm");

		return "0" + this.MM;
	};

	/** Returns the unit qualifier (an XFAUNIT* const value) from the qualified value. */
	this.getUnits = function(qValue)
	{
		if (!qValue || this._util.objType(qValue) != "string" || qValue.length < 3)
			return this.DEFAULT;

		var units = qValue.substr(qValue.length - 2, 2);

		switch (units)
		{
			case this.IN:
			case this.PT:
			case this.CM:
			case this.MM:
				// valid units
				break;

			default:
				units = this.DEFAULT;
				break;
		}

		return units;
	};

	/**
	 * Convert a qualified value from one unit type to another.
	 * @param mixed qValue Numeric value to convert. If this is a qualified value, the units will be ignored unless fromUnits is null.
	 * @param string fromUnits One of the unit const values from which to convert; value is treated as this type of unit. If null,
	 *  the function attempts to extract the unit from qValue.
	 * @param string toUnits One of the unit const value to which value will be converted.
	 * @return string Qualified value (measurement) resulting from the conversion to toUnits. If value was NaN, zero is returned.
	 */
	this.convert = function(qValue, fromUnits, toUnits)
	{
		if (!fromUnits)
			fromUnits = this.getUnits(qValue);

		if (fromUnits == toUnits)
			return qValue;

		var val = parseFloat(qValue);
		if (isNaN(val) || val == 0.0)
			val = 0;

		// normalize to mm since they're the most precise
		switch (fromUnits)
		{
			case this.IN:
				val = val * 25.4;
				break;

			case this.PT:
				val = val * (1/72) * 25.4;
				break;

			case this.CM:
				val = val * 10;
				break;

			case this.MM:
				break;

			default:
				this._debug.error("Units.convert -- invalid fromUnits '" + fromUnits + "'; unable to convert; returning original");
				return qValue;
				break;
		}

		// convert from mm to toUnits
		switch (toUnits)
		{
			case this.IN:
				val = val / 25.4;
				break;

			case this.PT:
				val = (val / 25.4) * 72;
				break;

			case this.CM:
				val = val / 10;
				break;

			case this.MM:
				break;

			default:
				this._debug.error("Units.convert -- invalid toUnits '" + toUnits + "'; unable to convert; returning in '" + this.MM + "'.");
				return val.toString() + this.MM;
				break;
		}

		return val.toString() + toUnits;
	};
} // end: UnitsClass()

//////////////////////////////////////////////
// Library Variables (always start with a '$'; private variables start with '_')
//

/** UtilClass: Utilities. */
var $util = new UtilClass();

/** ContextClass: Current library context. */
var $context = new ContextClass();

/** DebugClass: Debugging tools. */
var $debug = new DebugClass($context, $util);

/** UnitsClass: Units (XFA measurements) operations. */
var $units = new UnitsClass($util, $debug);

//////////////////////////////////////////////
// Library Functions (private functions start with '_')
//

/**
 * Sets the spacing between modules contained in the specified content target.
 *  Spacing is applied to every module contained in the target. This function
 *  can be called multiple times on the same target to set spacing in multiple
 *  locations.
 * @param subform targetSF The content target subform.
 * @param string spacing XFA measurement specifying the spacing to apply (e.g.
 *  '12pt' for 12 points, '1in' for 1 inch, etc.). Set to '0' to remove spacing.
 * @param string location The location to apply the spacing: 'left' for left
 *  spacing, 'right' for right spacing, 'above' for top/above spacing, 'below'
 *  for bottom/below spacing.
 */
function setContentTargetSpacing(targetSF, spacing, location)
{
	var funcName = "setContentTargetSpacing -- "; // for debug output

	if (targetSF == null || targetSF.className != "subform")
	{
		$debug.error(funcName + "invalid target subform" + (targetSF ? (": " + targetSF.somExpression) : ""));
		return;
	}
	else if (targetSF.resolveNode("iccModuleObject[0]") == null)
	{
		// target has no content
		return;
	}

	if (spacing == "")
	{
		$debug.error(funcName + "invalid spacing");
		return;
	}

	var marginMM = $units.valMM(spacing); // standardize on mm
	if (marginMM < 0)
		marginMM = 0;

	// The target subform will have been injected with the XFA Module Object which is (simplified):
	// <subformSet name='iccModuleObject'>
	//    <subform name="textModule">
	//       <field name="textContent"/>
	//    </subform>
	//    <subform name="imageModule">
	//       <field name="imageContent"/>
	//    </subform>
	// </subformSet>
	//
	// There will be one instance of iccModuleObject for every module in the target. Each instance will contain
	//  one instance of either textModule (for text content) or imageModule (for image content) subform.
	//
	// To add spacing on each module, the best way is to set the margins of the module subform instance (either
	//  textModule or imageModule depending on the data that was set on the instance of the iccModuleObject
	//  subform set). The module subform instance will contain either a textContent or imageContent field which
	//  will have a width set to that of the module subform instance. When setting the left or right margins
	//  on the module instance subform, we must remove the margin from the width of the field that is contained
	//  in the subform otherwise the field will overlap the subform.

	var moduleObjectSets = targetSF.iccModuleObject.all;
	for (var i = 0; i < moduleObjectSets.length; i++)
	{
		var moduleObjSFS = moduleObjectSets.item(i);
		var moduleSF = moduleObjSFS.resolveNode("#subform[0]"); // use resolveNode to make sure we get the module subform in the SF set instance
		if (moduleSF && (moduleSF.name == "textModule" || moduleSF.name == "imageModule"))
		{
			switch (location)
			{
				case "above":
					_setMISMargin(moduleSF, "topInset", marginMM);
					break;

				case "below":
					_setMISMargin(moduleSF, "bottomInset", marginMM);
					break;

				case "left":
					_setMISMargin(moduleSF, "leftInset", marginMM);
					break;

				case "right":
					_setMISMargin(moduleSF, "rightInset", marginMM);
					break;

				default:
					$debug.error(funcName + "invalid spacing location: " + location);
					break;
			}
		}
		else if (moduleSF)
			$debug.warning(funcName + "failed to locate 'textModule' or 'imageModule' subform in " + moduleObjSFS.somExpression);
		// else, the target has no module content
	}
}

/**
 * @private
 * Utility function to set a margin on a module instance subform (MIS).
 * @param subform sf The subform on which to set the margin.
 * @param string marginProp The name of the margin property to set: 'leftInset', 'rightInset', 'topInset',
 *  'bottomInset'.
 * @param number valueMM The margin value to set in mm.
 */
function _setMISMargin(sf, marginProp, valueMM)
{
	if (marginProp == "topInset" || marginProp == "bottomInset")
	{
		// just set the margin
		sf.margin[marginProp] = valueMM + $units.MM;
	}
	else
	{
		// either leftInset or rightInset

		var moduleField = (sf.name == "textModule" ? sf.textContent : sf.imageContent);
		if (!moduleField)
		{
			$debug.error("setContentTargetSpacing.setMargin -- failed to locate module content field in " + sf.somExpression);
			return;
		}

		var insetMM = $units.valMM(sf.margin[marginProp]); // current margin value
		var fieldWidthMM = $units.valMM(moduleField.w); // current field width

		fieldWidthMM += insetMM; // put the inset back-in to reset
		fieldWidthMM -= valueMM; // remove new margin from reset width
		moduleField.w = fieldWidthMM + $units.MM; // set new width (from which new margin has been removed) on field
		sf.margin[marginProp] = valueMM + $units.MM; // set new margin on subform
	}
}

//////////////////////////////////////////////
// ICC FormBridge Extensions (always in the form of 'icc{methodName}_FormBridge')
//
// WARNING: FormBridge APIs must return either strings or arrays of strings. Anything else is asking for trouble
//  due to the way data is communicated between the PDF and HTML layers.
//
// NOTE: Empty strings cannot be returned to Flex via FormBridge. They cause errors in the transmitted data. Also,
//  the value null cannot be returned because it becomes the string 'null'. Therefore, a special string is returned
//  to indicate when a value is empty/null: ICCFBEXT_EMPTY_VALUE.
//

//
// ICC FB Extension Constants (private constants start with '_')
//

/** string: Empty value identifier when sending empty/null values back to Flex. */
var ICCFBEXT_EMPTY_VALUE = "~iccEmpty~";

//
// ICC FB Extension Properties (private properties start with '_')
//

/** string: buffer of accumulated form data to be merged into the PDF's Data DOM. */
//commenting to avoid _setDataBuffer being reset again which was causing partial data to be transfered to PDF resulting in a blank PDF issue(bug##3125982)
//var _setDataBuffer = "";

//
// ICC FB Extension Methods (private methods start with '_')
//

/** Returns a reference to the FormBridge script object. */
function _formBridge()
{
	return xfa.form.resolveNode('$form..FormBridgeScriptBlock');
}

/**
 * ICC FormBridge Extension: For each specified form object SOM expression, determines the related Data SOM Expression
 *  and default value (if any).
 * @param AcroForm.Doc doc AcroForm PDF Document object.
 * @param array formSoms SOM expressions for form objects whose data information is to be retrieved.
 * @param param2 Unused.
 * @param param3 Unused.
 * @param param4 Unused.
 * @return array Array where each 3-element sequence represents the following:
 *  [n]   the form object SOM expression (from formSoms)
 *  [n+1] the associated Data SOM expression, or ICCFBEXT_EMPTY_VALUE if the object doesn't have a binding
 *        note that this will be the verbose SOM like 'xfa[0].datasets[0].data[0].form1[0].customer[0].address[0]' for a
 *         field bound to 'customer.address' from the root data node.
 *  [n+2] if the object is a field, its current value, or ICCFBEXT_EMPTY_VALUE if it doesn't have a value
 */
function iccGetDataInfo_FormBridge(doc, formSoms, param2, param3, param4)
{
	$debug.info("dataInfo: formSoms: " + formSoms);

	if (!formSoms || $util.objType(formSoms) != "array")
		throw "invalid SOM expression array";

	var dataInfo = new Array();
	for (var i = 0; i < formSoms.length; i++)
	{
		var som = formSoms[i];
		var formObj = null;
		try
		{
			formObj = xfa.form.resolveNode(som);
		}
		catch(exception)
		{
			$debug.error("dataInfo: exception while resolving SOM {" + som + "}:", exception);
			throw exception.toString();
		}

		if (!formObj)
		{
			$debug.error("dataInfo: failed to resolve SOM: " + som);
			throw "invalid SOM expression: did not resolve to a form object!";
		}

		// NOTE: do no set properties to null since that will result in the string 'null' in Flex and do not
		//  set them to empty strings either since that will cause errors when sending data back to Flex

		var dataSom = formObj.dataNode ? formObj.dataNode.somExpression : ICCFBEXT_EMPTY_VALUE;

		var value = ICCFBEXT_EMPTY_VALUE;
		if ((formObj.className == "field" || formObj.className == "exclGroup") && formObj.rawValue)
			value = formObj.rawValue;

		dataInfo.push(som, dataSom, value);
	}

	return dataInfo;
}

/**
 * ICC FormBridge Extension: Buffer a FormBridge setData() call so that large amounts of data can be successfully
 *  merged into the PDF. There seems to be a limit of ~28,000 UTF-8 characters when sending data from Flex to the
 *  PDF via FormBridge. This method lets the Flex app send the data is sequential calls before finally giving a
 *  command to set the accumulated data in the PDF via the traditional FormBridge setData() method.
 * @param AcroForm.Doc doc AcroForm PDF Document object.
 * @param string data Data to be accumulated in the buffer.
 * @param string command Accepted values are:
 *  start: replaces the buffer with the contents of the data parameter, effectively starting a new buffered sequence.
 *  append: appends the specified data to the buffer; no validation is done on the data.
 *  commit: accumulates the contents of the data parameter, if it isn't ICCFBEXT_EMPTY_VALUE, sets the buffered data in
 *   the PDF's Data DOM, and clears the buffer.
 * @param param3 optional data som expression.
 * @param param4 Unused.
 * @return void
 */
function iccSetDataBuffer_FormBridge(doc, data, command, param3, param4)
{
	$debug.info("setDataBuffer: command: " + command + ", data:\n" + data);

	if (data == ICCFBEXT_EMPTY_VALUE)
		data = "";

	switch (command)
	{
		case "start":
			_setDataBuffer = data;
			break;

		case "append":
			_setDataBuffer += data;
			break;

		case "commit":
		{
			_setDataBuffer += data; // accumulate remaining data, if any

			try
			{
                if(!param3)
                {
                    $debug.info("setDataBuffer: committing buffered data:\n" + _setDataBuffer);
                    _formBridge().setData(_setDataBuffer); // make sure we find the FormBridge wherever it is defined
                    // do not execute any other code after this call -- if it succeeds, the form will be reset immediately
                }
                else
                {
                    $debug.info("setDataBuffer: committing buffered data:\n" + _setDataBuffer+ ":"+param3);
                    _formBridge().setSOMProperties(param3, ["objectXml"], [_setDataBuffer]);
                }
			}
			catch(exception)
			{
				$debug.error("setDataBuffer: exception while setting buffered data:", exception);
				throw exception.toString();
			}

			break;
		}

		default:
			throw ("invalid command: " + command);
			break;
	}

	// do not execute any other code here if the setData() call succeeded -- the form have been reset immediately
}

/**
 * ICC FormBridge Extension: Sets the highlighting on a given targets subform and set focus on first highlight target.
 * @param params The array of parameters to be passed for highlighting.
 * 'params' is supposed to be in order: ( ex :  ["form1[0].Sub[0].Subform1[0].ModuleContainer[0],0:0,false,false,false",border,90;155;245,fill,210;225;245,false]  )
 * targetSOMArray = params[0]; (Comma seprated value of (targetSom,index,isImage,highlight,setFocus) ex : (form1[0].Sub[0].Subform1[0].ModuleContainer[0],0:0,false,false,false))
 * targetHighlightType = params[1];
 * targetColor = params[2];
 * contentHighlightType = params[3];
 * contentColor = params[4];
 * @param param2 Unused.
 * @param param3 Unused.
 * @param param4 Unused.
 */
function iccSetContentMultipleTargetHighlight_FormBridge(doc, params, param2, param3, param4)
{
   var targetSOMArray = params[0].split(",");
   var targetHighlightType = params[1];
   var targetColor = params[2];
   var contentHighlightType = params[3];
   var contentColor = params[4];   

   var setFocus,targetSOM,index,isImage,highlight;
   var targetElement;
   var highlightTarget;
   var i=0;
   while(i < targetSOMArray.length){
   	 targetSOM = targetSOMArray[i];i++;   
   	 index = targetSOMArray[i];i++;   
   	 isImage= targetSOMArray[i];i++;   
     highlight = targetSOMArray[i];i++;    
	 setFocus = targetSOMArray[i];i++;    
   	 highlightTarget= [];
   	 highlightTarget.push(targetSOM);
   	 highlightTarget.push(index); 
   	 highlightTarget.push(isImage); 
	 highlightTarget.push(highlight);
	 highlightTarget.push(targetHighlightType);
	 highlightTarget.push(targetColor);
	 highlightTarget.push(contentHighlightType);
	 highlightTarget.push(contentColor);
	 highlightTarget.push(setFocus);
	 iccSetContentTargetHighlight_FormBridge(doc,highlightTarget);
   }
}


// previous values for restoring (default to WHITE)
var targetPrevBorderVisibility = null;
var targetPrevFillVisibility = null;
var targetPrevColor = null;
var targetPrevThickness = null;
/**
 * ICC FormBridge Extension: Sets the focus and highlighting on a given target subform.
 * @param params The array of parameters to be passed for highlighting.
 * 'params' is supposed to be in order:
 * targetSOM = params[0];
 * index = params[1];
 * isImage = params[2];
 * highlight = params[3];
 * targetHighlightType = params[4];
 * targetColor = params[5];
 * contentHighlightType = params[6];
 * contentColor = params[7];
 * @param param2 Unused.
 * @param param3 Unused.
 * @param param4 Unused.
 */
function iccSetContentTargetHighlight_FormBridge(doc, params, param2, param3, param4)
{
   $debug.info(params);

   if (!params || $util.objType(params) != "array")
       throw "invalid input parameters";


   // 'params' is supposed to be in order:

   var targetSOM = params[0];
   var index = params[1];
   var isImage = params[2];
   var highlight = params[3];

   var targetHighlightType = params[4];
   var targetColor = params[5];
   var contentHighlightType = params[6];
   var contentColor = params[7];
   var setFocus;
   if(params[10] == undefined)   
		setFocus = highlight;
   else
   		setFocus = params[8];   

   if (!targetSOM || !index || !isImage || !highlight)
       throw "invalid input params specified.";

   // First, identify and highlight the Target area
   var targetObj = null;
   try
   {
       targetObj = xfa.form.resolveNode(targetSOM);
   }
   catch(exception)
   {
       $debug.error("setContentTargetHighlight: exception while resolving SOM {" + targetSOM + "}:", exception);
       throw exception.toString();
   }

   if (!targetObj)
   {
       $debug.error("setContentTargetHighlight: failed to resolve SOM: " + targetSOM);
       throw "invalid SOM expression: did not resolve to a form object!";
   }

   if (highlight == "true")
   {
		targetColor = targetColor.replace(/;/g, ",");
       if (targetHighlightType == "border")
       {
    	    // backup previous value to restore
    	    if (targetPrevColor == null || targetPrevThickness == null || targetPrevBorderVisibility == null)
    	    {
	    	    targetPrevColor = targetObj.border.edge.color.value;
	    	    targetPrevThickness = targetObj.border.edge.thickness;
	    	    targetPrevBorderVisibility = targetObj.border.presence;
    	    }

	        targetObj.border.presence = "visible";
	        targetObj.border.edge.color.value = targetColor;
	        targetObj.border.edge.thickness="4px";
	    }
	    else if (targetHighlightType == "fill")
	    {
	    	// backup previous value to restore
	    	if (targetPrevColor == null || targetPrevBorderVisibility == null || targetPrevFillVisibility == null)
    	    {
	    	    targetPrevColor = targetObj.fillColor;
	    	    targetPrevBorderVisibility = targetObj.border.presence;
	    	    targetPrevFillVisibility = targetObj.border.fill.presence;
    	    }

	        targetObj.border.presence = "visible";
	        targetObj.border.fill.presence = "visible";
            targetObj.fillColor = targetColor;
	    }
   }
   else 
   {
      if (targetHighlightType == "border")
      {
    	  if (targetPrevColor != null && targetPrevThickness != null && targetPrevBorderVisibility != null)
    	  {
	          targetObj.border.presence = targetPrevBorderVisibility;
	          targetObj.border.edge.color.value = targetPrevColor;
	          targetObj.border.edge.thickness = targetPrevThickness;
    	  }
      }
      else if (targetHighlightType == "fill")
      {
    	  if (targetPrevColor != null && targetPrevBorderVisibility != null && targetPrevFillVisibility == null)
    	  {
	          targetObj.border.presence = targetPrevBorderVisibility;
	          targetObj.border.fill.presence = targetPrevFillVisibility;
	          targetObj.fillColor = targetPrevColor;
    	  }
      }

      // reset after restoring values
      targetPrevBorderVisibility = null;
      targetPrevFillVisibility = null;
      targetPrevColor = null;
      targetPrevThickness = null;
   }


   // Now, identify the actual '(text/image)Content' Field and highlight/set-focus-on the same

   var temp = new Array();
   temp = index.split(':');

   var overallIndex = temp[0];
   var moduleIndex = temp[1];

   if (moduleIndex != "-1" && overallIndex != "-1") // expecting -1 if no module was selected (but only a container - List/Condition)
   {

       var moduleObj = null;
       var indentObj = null;
       var indentSOM = null;
       var moduleSOM = "";

       if (isImage == "true") // select Image Field
       {
           moduleSOM = targetSOM + ".iccModuleObject[" + overallIndex + "].imageModule[" + moduleIndex + "].imageContent[0]";
           indentSOM = targetSOM + ".iccModuleObject[" + overallIndex + "].imageModule[" + moduleIndex + "].indent[0]";
       }
       else  // select Text Field
       {
           moduleSOM = targetSOM + ".iccModuleObject[" + overallIndex + "].textModule[" + moduleIndex + "].textContent[0]";
           indentSOM = targetSOM + ".iccModuleObject[" + overallIndex + "].textModule[" + moduleIndex + "].indent[0]";
       }

	    try
	    {
	        moduleObj = xfa.form.resolveNode(moduleSOM);
	        indentObj = xfa.form.resolveNode(indentSOM);
	    }
	    catch(exception)
	    {
	        $debug.error("setContentTargetHighlight: exception while resolving SOM {" + moduleSOM + "}:", exception);
	        throw exception.toString();
	    }

	    if (!moduleObj)
	    {
	        $debug.error("setContentTargetHighlight: failed to resolve SOM: " + moduleSOM);
	        throw "invalid SOM expression: did not resolve to a form object!";
	    }

	    if (highlight == "true")
	    {
	    	contentColor = contentColor.replace(/;/g, ",");
	        if (contentHighlightType == "border")
	        {
	           moduleObj.border.presence = "visible";
               moduleObj.border.edge.color.value = contentColor;
               moduleObj.border.edge.thickness="4px";
	        }
	        else if (contentHighlightType == "fill")
	        {
	            moduleObj.border.presence = "visible";
	            moduleObj.border.fill.presence = "visible";
	            moduleObj.fillColor = contentColor;
	            moduleObj.border.edge.color.value = "255,255,255"; // avoid a black border outline
	        }
	        if(setFocus == "true")
				xfa.host.setFocus(indentObj.somExpression);
	    }
	    else 
	    {
	       if (contentHighlightType == "border")
	        {
	            moduleObj.border.presence = "invisible";
	            moduleObj.border.edge.color.value = "255,255,255";
	            moduleObj.border.edge.thickness="0mm";
	        }
	        else if (contentHighlightType == "fill")
	        {
	            moduleObj.border.presence = "invisible";
	            moduleObj.border.fill.presence = "invisible";
	            moduleObj.fillColor = "255,255,255";
	        }
	    }
   }  
/*   else
   {
   	// a container/un-selected module is being focussed. we do not need to set focus in this case. 
   	// Corresponding target area's border will be highlighted in the begining of this function.
   } */
}

//previous values for restoring (default to WHITE)
var fieldPrevBorderVisibility = null;
var fieldPrevFillVisibility = null;
var fieldPrevColor = null;
var fieldPrevThickness = null;

/**
 * ICC FormBridge Extension: Sets the focus and highlighting on a given Field.
 * @param params The array of parameters to be passed for highlighting.
 * 'params' is supposed to be in order:
 * fieldSOM = params[0];
 * highlight = params[1];
 * fieldHighlightType = params[2];
 * fieldColor = params[3];
 * @param param2 Unused.
 * @param param3 Unused.
 * @param param4 Unused.
 */
function iccSetFieldHighlight_FormBridge(doc, params, param2, param3, param4)
{
   $debug.info(params);

   if (!params || $util.objType(params) != "array")
       throw "invalid input parameters";


   // 'params' is supposed to be in order:

   var fieldSOM = params[0];
   var highlight = params[1];

   var fieldHighlightType = params[2];
   var fieldColor = params[3];

   if (!fieldSOM || !highlight)
       throw "invalid input params specified.";

   // First, identify and highlight the Target area
   var fieldObj = null;
   try
   {
       fieldObj = xfa.form.resolveNode(fieldSOM);
   }
   catch(exception)
   {
       $debug.error("setFieldHighlight: exception while resolving SOM {" + fieldSOM + "}:", exception);
       throw exception.toString();
   }

   if (!fieldObj)
   {
       $debug.error("setFieldHighlight: failed to resolve SOM: " + fieldSOM);
       throw "invalid SOM expression: did not resolve to a form object!";
   }

   if (highlight == "true")
   {
   	   fieldColor = fieldColor.replace(/;/g, ",");
       if (fieldHighlightType == "border")
       {
    	   // backup previous value to restore later
    	   if (fieldPrevColor == null || fieldPrevThickness == null || fieldPrevBorderVisibility == null)
    	   {
	    	   fieldPrevColor = fieldObj.border.edge.color.value;
	    	   fieldPrevThickness = fieldObj.border.edge.thickness;
	    	   fieldPrevBorderVisibility = fieldObj.border.presence;
   	       }

           fieldObj.border.presence = "visible";
           fieldObj.border.edge.color.value = fieldColor;
           fieldObj.border.edge.thickness="4px";
       }
       else if (fieldHighlightType == "fill")
       {
    	   // backup previous value to restore later
    	   if (fieldPrevColor == null || fieldPrevBorderVisibility == null || fieldPrevFillVisibility == null)
    	   {
	    	   fieldPrevColor = fieldObj.fillColor;
	    	   fieldPrevBorderVisibility = fieldObj.border.presence;
	    	   fieldPrevFillVisibility = fieldObj.border.fill.presence;
    	   }

           fieldObj.border.presence = "visible";
           fieldObj.border.fill.presence = "visible";
           fieldObj.fillColor = fieldColor;
       }

       xfa.host.setFocus(fieldObj.somExpression);
   }
   else 
   {
      if (fieldHighlightType == "border")
      {
    	  if (fieldPrevColor != null && fieldPrevThickness != null && fieldPrevBorderVisibility == null)
    	  {
	          fieldObj.border.presence = fieldPrevBorderVisibility;
	          fieldObj.border.edge.color.value = fieldPrevColor;
	          fieldObj.border.edge.thickness = fieldPrevThickness;
    	  }
      }
      else if (fieldHighlightType == "fill")
      {
    	  if (fieldPrevColor != null && fieldPrevBorderVisibility != null && fieldPrevFillVisibility != null)
   	   	  {
	          fieldObj.border.presence = fieldPrevBorderVisibility;
	          fieldObj.border.fill.presence = fieldPrevFillVisibility;
	          fieldObj.fillColor = fieldPrevColor;
   	   	  }
      }

      // reset after restoring value
      fieldPrevBorderVisibility = null;
      fieldPrevFillVisibility = null;
      fieldPrevColor = null;
      fieldPrevThickness = null;
   }
}


/**
* ICC FormBridge Extension: remerges data with form.
*/
function iccRemergeData_FormBridge()
{
    xfa.datasets.saveXML();
    xfa.form.remerge();
    // perform a relayout, in case there is a need (due to data based layout changes)
    xfa.layout.relayout();
    xfa.layout.relayout();
}

/**
* ICC FormBridge Extension: Sets the value for data node binded to field
*/
function iccSetFieldDataNode_FormBridge(doc, fieldSom, fieldDataSom, fieldValueXml)
{
    //Need to set the rawValue to null else value would be appended to existing value. A workaround to existing bug
    xfa.form.resolveNode(fieldSom).rawValue = "";
    xfa.resolveNode(fieldDataSom).loadXML(fieldValueXml, 1, 1);
    //Need to reload root xml other wise datanode changes are not reflected. Workaround for a bug
    var tmpData = xfa.datasets.saveXML();
    xfa.datasets.loadXML(tmpData, 1, 1);
    xfa.form.remerge();
    // perform a relayout, in case there is a need (due to data based layout changes)
    xfa.layout.relayout();
    xfa.layout.relayout();
}

/**
Sets page break setting for a module.
@param obj text or image module on which page break setting is required to be applied.
*/
function setPageBreak(obj)
{
	if (obj.dataNode.pageLayout.noPageBreak && obj.dataNode.pageLayout.noPageBreak.value == "true") {
		obj.parent.parent.keep.intact = "contentArea";
	}
	if (obj.dataNode.pageLayout.keepWithNext && obj.dataNode.pageLayout.keepWithNext.value == "true") {
		obj.parent.parent.keep.next = "contentArea";
	}
	if(obj.dataNode.pageLayout.pageBreakBefore && obj.dataNode.pageLayout.pageBreakBefore.value == "true") {
		obj.parent.parent.break.startNew="1";
		obj.parent.parent.break.before="pageArea";
	}
	if(obj.dataNode.pageLayout.pageBreakAfter && obj.dataNode.pageLayout.pageBreakAfter.value == "true") {
		obj.parent.parent.break.startNew="1";
		obj.parent.parent.break.after="pageArea";	       
	}
}
